/**
 * OKKI 一键同步脚本
 *
 * 自动检测浏览器状态 → 登录 → 导航TM → 提取会话元数据 → 增量拉消息
 *
 * 用法：node scripts/sync_okki.js
 *
 * 适用所有场景：
 * - 刚开机/Chrome没开/没登录 → 自动启动Chrome → 等你登录 → 继续
 * - Chrome开着+已登录+在TM页 → 直接抓取
 * - Chrome开着但不在TM页 → 自动导航
 */

const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');
const http = require('http');

const PROFILE = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
const DATA_DIR = path.join(__dirname, '..', 'data');
const CHAT_DIR = path.join(DATA_DIR, 'chat_history');
const CDP_URL = 'http://localhost:9222';
const MSG_COUNT = 50;
const MAX_PAGES = 20;

// ===================== 工具函数 =====================

function ts() { return new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19); }
function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }
function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

function sanitizeFilename(cid) {
  return cid.replace(/[<>:"/\\|?*#@]/g, '_').substring(0, 200);
}

// ===================== CDP 端口检测 =====================

function checkCdpPort() {
  return new Promise((resolve) => {
    const req = http.get('http://127.0.0.1:9222/json/version', (res) => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(!!json.webSocketDebuggerUrl);
        } catch (e) { resolve(false); }
      });
    });
    req.on('error', () => resolve(false));
    req.setTimeout(2000, () => { req.destroy(); resolve(false); });
  });
}

// ===================== 主流程 =====================

async function main() {
  let browser;
  let page;
  let useCdp = false;

  // ---- Step 1: 启动/连接浏览器 ----
  const cdpAvailable = await checkCdpPort();
  if (cdpAvailable) {
    log('检测到 CDP 端口，尝试连接已有 Chrome...');
    try {
      browser = await chromium.connectOverCDP(CDP_URL);
      const pages = browser.contexts()[0]?.pages() || [];
      page = pages.find(p => p.url().includes('xiaoman') || p.url().includes('onetalk'));
      if (!page) {
        page = await browser.contexts()[0].newPage();
      }
      useCdp = true;
      log(`CDP 已连接。当前页面: ${page.url()}`);
    } catch (e) {
      log(`CDP 连接失败: ${e.message}，改用独立启动模式`);
    }
  }

  if (!browser) {
    log('启动 Chrome (Profile 4)...');
    browser = await chromium.launchPersistentContext(PROFILE, {
      channel: 'chrome',
      headless: false,
      viewport: { width: 1440, height: 900 },
    });
    page = await browser.newPage();
    log('Chrome 已启动');
  }

  // ---- Step 2: 导航到 OKKI + 登录检测 ----
  const currentUrl = page.url();
  if (!currentUrl.includes('xiaoman') && !currentUrl.includes('onetalk') && !currentUrl.includes('alibaba')) {
    log('导航到 crm.xiaoman.cn...');
    await page.goto('https://crm.xiaoman.cn/', { waitUntil: 'domcontentloaded', timeout: 30000 });
  }

  // 检测登录状态
  let loginUrl = page.url();
  if (loginUrl.includes('login.xiaoman.cn') || loginUrl.includes('login.alibaba.com')) {
    log('');
    log('========================================');
    log('  请在浏览器中登录 OKKI (小满)');
    log('  登录后脚本自动继续...');
    log('========================================');
    log('');

    const startTime = Date.now();
    const maxWait = 5 * 60 * 1000;
    while (Date.now() - startTime < maxWait) {
      const url = page.url();
      if (!url.includes('login.xiaoman.cn') && !url.includes('login.alibaba.com') && url.includes('crm.xiaoman.cn')) {
        log('登录成功！');
        break;
      }
      await sleep(2000);
    }
    if (page.url().includes('login')) {
      log('超时：未检测到登录。退出。');
      await browser.close();
      process.exit(1);
    }
  } else {
    log('已登录状态');
  }

  // ---- Step 3: 导航到 TM 消息页面 ----
  log('导航到 TM 消息页...');
  await page.goto('https://crm.xiaoman.cn/im/', { waitUntil: 'domcontentloaded', timeout: 30000 }).catch(() => {});
  await sleep(3000);

  // 可能需要点击侧边栏进入 TM（OKKI 的 /im/ 可能只显示外壳，onetalk 在 iframe 里）
  log(`当前 URL: ${page.url()}`);

  // ---- Step 4: 等待 onetalk iframe + 数据就绪 ----
  log('等待 onetalk iframe 加载...');

  // 递归查找 onetalk 页面（可能在嵌套 iframe 中）
  function findOnetalkFrame(pageOrFrame) {
    const frames = pageOrFrame.frames ? pageOrFrame.frames() : (pageOrFrame.childFrames ? pageOrFrame.childFrames() : []);
    for (const f of frames) {
      const url = f.url();
      // 真正的 onetalk PWA 页面，不是 OKKI 外壳
      if (url.startsWith('https://onetalk.alibaba.com/')) return f;
      // 递归查找
      const found = findOnetalkFrame(f);
      if (found) return found;
    }
    return null;
  }

  let iframePage = null;
  for (let attempt = 0; attempt < 30; attempt++) {
    iframePage = findOnetalkFrame(page);
    if (iframePage) {
      log(`onetalk iframe 已找到 (尝试 ${attempt + 1}): ${iframePage.url().slice(0, 100)}`);
      break;
    }
    if (attempt === 0) {
      const bodyText = await page.evaluate(() => document.body.innerText?.slice(0, 500)).catch(() => '');
      log(`  页面预览: ${bodyText.slice(0, 200)}`);
      // 检查是否在 OKKI 外壳中
      const allFrames = page.frames();
      log(`  当前 ${allFrames.length} 个 frame:`);
      for (const f of allFrames) {
        log(`    ${f.url().slice(0, 120)}`);
      }
    }
    await sleep(2000);
  }

  if (!iframePage) {
    log('iframe 未找到。请确认：');
    log('  1. 已退出手机阿里卖家');
    log('  2. OKKI TM 面板不是 "Click to retry" 状态');
    log('  3. TM 面板中能看到会话列表');
    log('');
    log('脚本保持运行。完成上述操作后回车继续...');
    await new Promise(() => {});
  }

  // ---- Step 5: 提取会话列表（带重试） ----
  log('提取会话元数据...');
  let convData = null;
  for (let attempt = 0; attempt < 20; attempt++) {
    convData = await iframePage.evaluate(() => {
      const convs = window.__conversationListFullData__;
      if (!convs || !Array.isArray(convs)) return { error: 'no __conversationListFullData__', type: typeof convs, count: 0 };
      return {
        count: convs.length,
        list: convs.map(c => ({
          cid: c.cid,
          name: c.name,
          loginId: c.loginId,
          aliId: c.aliId,
          accountId: c.accountId,
          companyName: c.companyName,
          country: c.country,
          level: c.level,
          serviceType: c.serviceType,
          conversationType: c.conversationType,
          unreadCount: c.unreadCount,
          stayTop: c.stayTop,
          lastContactTime: c.lastContactTime,
          lastContactTimeLong: c.lastContactTimeLong,
          createAt: c.createAt,
          tagInfo: c.tagInfo,
          available: c.available,
          complianceCountryCode: c.complianceCountryCode,
          latestMessage: c.latestMessage ? {
            content: c.latestMessage.content,
            messageType: c.latestMessage.messageType,
            messageId: c.latestMessage.messageId,
            gmtChat: c.latestMessage.gmtChat,
            contactRead: c.latestMessage.contactRead,
          } : null,
        })),
      };
    }).catch(e => ({ error: e.message, count: 0 }));

    if (!convData.error && convData.count > 0) {
      log(`提取成功: ${convData.count} 个会话 (尝试 ${attempt + 1})`);
      break;
    }
    if (attempt === 0) {
      log(`  等待 TM 数据加载 (${convData.error || '空数据'})...`);
    }
    await sleep(2000);
  }

  if (!convData || convData.error || convData.count === 0) {
    log(`提取失败: ${convData?.error || '无数据'}`);
    log('TM 面板可能未正常加载。请确认能看到会话列表后重新运行脚本。');
    await browser.close();
    process.exit(1);
  }

  // 展平结果
  const convList = convData.list;
  const totalCount = convData.count;

  log(`提取到 ${totalCount} 个会话`);

  // ---- Step 6: 保存最新元数据 ----
  const latestMeta = {
    exportedAt: new Date().toISOString(),
    total: totalCount,
    conversations: convList,
  };
  const metaPath = path.join(DATA_DIR, 'tm_conversations_latest.json');
  fs.writeFileSync(metaPath, JSON.stringify(latestMeta, null, 2));
  log(`元数据已保存: tm_conversations_latest.json (${totalCount} 会话)`);

  // ---- Step 7: Diff 找出变化的会话 ----
  log('对比上次数据...');
  let oldMeta = null;
  const oldPath = path.join(DATA_DIR, 'tm_conversations_full.json');
  if (fs.existsSync(oldPath)) {
    oldMeta = JSON.parse(fs.readFileSync(oldPath, 'utf-8'));
  }

  const changed = [];
  const oldMap = new Map();
  if (oldMeta?.conversations) {
    for (const c of oldMeta.conversations) {
      oldMap.set(c.cid, c);
    }
  }

  for (const c of convList) {
    const old = oldMap.get(c.cid);
    if (!old) {
      // 新会话
      changed.push({ cid: c.cid, name: c.name, reason: '新会话', oldLmId: null, newLmId: c.latestMessage?.messageId });
      continue;
    }
    const oldLmId = old.latestMessage?.messageId;
    const newLmId = c.latestMessage?.messageId;
    const oldLct = old.lastContactTime || 0;
    const newLct = c.lastContactTime || 0;

    if (oldLmId !== newLmId || newLct > oldLct) {
      const reason = oldLmId !== newLmId ? '消息更新' : '时间更新';
      changed.push({ cid: c.cid, name: c.name, reason, oldLmId, newLmId });
    }
  }

  log(`变化会话: ${changed.length} 个`);
  if (changed.length > 0) {
    for (const ch of changed.slice(0, 15)) {
      log(`  ${ch.reason}: ${ch.name}`);
    }
    if (changed.length > 15) log(`  ... 共 ${changed.length} 个`);
  }

  // ---- Step 8: 增量拉取聊天历史 ----
  if (changed.length === 0) {
    log('无变化，无需拉取聊天历史。同步完成。');
    printSummary(convList, changed);
    await browser.close();
    return;
  }

  log('');
  log(`开始增量拉取 ${changed.length} 个会话的聊天历史...`);

  // 获取 CDP session
  let cdpClient;
  let iframeSessionId;

  if (!useCdp) {
    // Playwright 启动模式: 需要通过 CDP 访问 iframe
    cdpClient = await page.context().newCDPSession(page);
    const targets = await cdpClient.send('Target.getTargets');
    const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
    if (ot) {
      const attached = await cdpClient.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });
      iframeSessionId = attached.sessionId;
      log(`CDP attached to onetalk iframe: ${ot.url.slice(0, 80)}`);
    } else {
      log('警告: 未找到 onetalk iframe target，尝试用 page.frames() 方式...');
    }
  } else {
    // CDP 连接模式: page 已经是 CDP 连接的
    cdpClient = await page.context().newCDPSession(page);
    const targets = await cdpClient.send('Target.getTargets');
    const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
    if (!ot) {
      // 检查 page 本身是否是 onetalk
      if (page.url().includes('onetalk')) {
        iframeSessionId = undefined; // page 本身就是 onetalk
        log('当前页面就是 onetalk');
      } else {
        log('警告: 未找到 onetalk target');
      }
    } else {
      const attached = await cdpClient.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });
      iframeSessionId = attached.sessionId;
      log(`CDP attached to onetalk iframe`);
    }
  }

  // 安装 LWP 收发器
  if (iframeSessionId || page.url().includes('onetalk')) {
    log('安装 LWP 收发器...');
    await installLwp(cdpClient, iframeSessionId);
    await sleep(3000);

    // 确认 WS 已捕获
    const wsState = await evalInIframe(cdpClient, iframeSessionId, 10,
      `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`
    );
    log(`WS 状态: ${JSON.stringify(wsState)}`);

    if (!wsState?.ws) {
      log('等待 WebSocket 连接...');
      await sleep(15000);
      const wsState2 = await evalInIframe(cdpClient, iframeSessionId, 11,
        `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`
      );
      log(`WS 状态(重试): ${JSON.stringify(wsState2)}`);
    }

    // 拉取消息
    let pulled = 0;
    let errors = 0;
    let totalNewMsgs = 0;
    let msgIdCounter = 100;

    for (let i = 0; i < changed.length; i++) {
      const conv = changed[i];
      try {
        const allMessages = [];
        let cursor = 9007199254740991;
        let pageNum = 0;

        while (pageNum < MAX_PAGES) {
          const msgId = msgIdCounter++;
          const raw = await evalInIframe(cdpClient, iframeSessionId, msgId,
            `(async function() {
              try {
                var result = await window.__lwpRequest('/r/MessageManager/listUserMessages', ['${conv.cid}', false, ${cursor}, ${MSG_COUNT}, false]);
                return JSON.stringify(result);
              } catch(e) {
                return JSON.stringify({ __error: e.message });
              }
            })()`,
            true
          );

          await sleep(1500);

          if (!raw || raw.__error) {
            if (raw?.__error === 'timeout') { log(`  [${conv.name}] LWP超时`); }
            break;
          }

          let response;
          try { response = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { break; }
          if (response.code !== 200) break;

          const body = response.body;
          if (!body?.userMessageModels || body.userMessageModels.length === 0) break;

          allMessages.push(...body.userMessageModels);

          if (body.userMessageModels.length < MSG_COUNT || !body.nextCursor) break;
          cursor = body.nextCursor;
          pageNum++;
        }

        // 保存
        const safeName = sanitizeFilename(conv.cid);
        const output = {
          cid: conv.cid,
          name: conv.name,
          fetchedAt: new Date().toISOString(),
          totalMessages: allMessages.length,
          messages: allMessages,
        };
        fs.writeFileSync(path.join(CHAT_DIR, safeName + '.json'), JSON.stringify(output, null, 2));
        pulled++;
        totalNewMsgs += allMessages.length;
        if (allMessages.length > 0) {
          log(`  [${i+1}/${changed.length}] ${conv.name}: ${allMessages.length} 条消息`);
        }
      } catch (e) {
        errors++;
        if (errors <= 5) log(`  [${conv.name}] 错误: ${e.message}`);
      }
    }

    log(`拉取完成: ${pulled} 个会话, ${totalNewMsgs} 条消息, ${errors} 个错误`);
  } else {
    log('跳过 LWP 拉取（无 CDP/iframe 访问）');
    log('已保存元数据差异。在新对话中可通过 STATE.md 了解哪些客户需要深抓。');
  }

  // ---- Step 9: 输出摘要 ----
  printSummary(convList, changed);
  await browser.close();
  log('同步完成。');
